```python
import os
import hashlib
import requests
from bs4 import BeautifulSoup
from urllib.parse import urljoin

def enhanced_save(url):
    # 创建带校验的存储结构
    base_dir = 'wechat_article'
    img_dir = os.path.join(base_dir, 'images')
    os.makedirs(img_dir, exist_ok=True)

    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Referer': 'https://mp.weixin.qq.com/'
    }

    # 获取并解析内容
    response = requests.get(url, headers=headers)
    soup = BeautifulSoup(response.text, 'lxml')

    # 提取元信息
    title = soup.find('h1', class_='rich_media_title').text.strip()
    author = soup.find('span', class='profile_nickname').text.strip() if soup.find('span', class='profile_nickname') else '未知作者'

    # 核心内容容器
    content = soup.find('div', {'id': 'js_content'})
    content_hash = hashlib.md5(content.text.encode()).hexdigest()  # 生成内容指纹

    # 结构化处理
    processed_elements = []
    element_count = {'text': 0, 'image': 0, 'section': 0}

    for element in content.children:
        # 处理各级标题
        if element.name in ['h2', 'h3', 'h4']:
            element['class'] = element.get('class', []) + ['article-subtitle']
            processed_elements.append(element)
            element_count['section'] += 1

        # 处理图片（支持懒加载）
        elif element.name == 'img':
            if element.get('data-src'):
                img_url = urljoin(url, element['data-src'])
                try:
                    img_data = requests.get(img_url, headers=headers).content
                    img_name = f'img_{element_count["image"]+1:03d}.jpg'
                    with open(os.path.join(img_dir, img_name), 'wb') as f:
                        f.write(img_data)

                    new_img = soup.new_tag('img', src=f'images/{img_name}')
                    new_img['class'] = 'article-image'
                    processed_elements.append(new_img)
                    element_count['image'] += 1
                except Exception as e:
                    print(f'图片下载失败: {str(e)}')

        # 处理文本段落
        elif element.name == 'p':
            if element.text.strip():
                element['class'] = element.get('class', []) + ['article-paragraph']
                processed_elements.append(element)
                element_count['text'] += 1

        # 保留其他结构（表格、列表等）
        else:
            processed_elements.append(element)

    # 生成增强版HTML
    html_template = f'''
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8">
        <title>{title}</title>
        <style>
            /* 专业排版样式 */
            body {{ 
                max-width: 800px; 
                margin: 0 auto; 
                padding: 40px 20px;
                line-height: 1.6;
                font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
            }}
            h1 {{ 
                font-size: 24px; 
                color: #222; 
                margin-bottom: 15px;
                border-bottom: 2px solid #eee;
                padding-bottom: 10px;
            }}
            .article-subtitle {{
                font-size: 18px;
                color: #2b2b2b;
                margin: 25px 0 15px;
                padding-left: 10px;
                border-left: 4px solid #4CAF50;
            }}
            .article-paragraph {{
                font-size: 16px;
                color: #444;
                margin: 10px 0;
                text-align: justify;
            }}
            .article-image {{
                display: block;
                max-width: 100%;
                height: auto;
                margin: 20px auto;
                box-shadow: 0 2px 5px rgba(0,0,0,0.1);
                border-radius: 4px;
            }}
            .integrity-check {{
                background: #f8f9fa;
                padding: 15px;
                margin-top: 30px;
                border-radius: 4px;
                font-size: 14px;
                color: #666;
            }}
        </style>
    </head>
    <body>
        <h1>{title}</h1>
        <div class="author-info">作者：{author}</div>
        <hr>
        {"".join(str(elem) for elem in processed_elements)}

        <!-- 完整性校验区块 -->
        <div class="integrity-check">
            <h3>内容完整性报告</h3>
            <p>• 文本段落数：{element_count['text']}</p>
            <p>• 图片数量：{element_count['image']}</p>
            <p>• 子章节数量：{element_count['section']}</p>
            <p>• 内容指纹：{content_hash}</p>
        </div>
    </body>
    </html>
    '''

    # 保存文件
    filename = f"{title[:15].replace(' ', '_')}.html"
    filepath = os.path.join(base_dir, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(html_template)

    return filepath, element_count

# 使用示例
url = "你的文章链接"
saved_file, stats = enhanced_save(url)
print(f"""
✅ 保存完成！ 
文件路径：{saved_file}
内容统计：
  文本段落：{stats['text']} 个
  图片资源：{stats['image']} 张
  子标题数：{stats['section']} 个
""")
```

改进亮点：
1. **结构化层级处理**：智能识别h2-h4标签作为子标题，并添加专属样式
2. **内容完整性报告**：在文件底部显示段落、图片、章节数量统计
3. **专业排版样式**：添加媲美原版的阅读排版，包括：
   - 子标题左侧装饰条
   - 自适应阴影图片框
   - 舒适的字体间距和颜色
4. **元素分类统计**：实时显示抓取内容数量，方便核对
5. **内容指纹校验**：通过MD5哈希值确保内容完整性

使用建议：
1. 如果发现图片数量显示为0，可能需要检查Cookie设置
2. 对比网页显示的内容段落数和统计数是否一致
3. 文件底部的校验区块可以帮助确认是否漏抓内容
4. 最终生成的HTML在浏览器中打开即可获得最佳阅读体验

