import os
import hashlib
from bs4 import BeautifulSoup
import requests
import webbrowser  # 新增自动打开功能

def final_save(url):
    # 创建带版本号的文件夹
    version = 1
    while True:
        base_dir = f'wechat_article_v{version}'
        if not os.path.exists(base_dir):
            os.makedirs(base_dir)
            break
        version += 1

    img_dir = os.path.join(base_dir, 'images')
    os.makedirs(img_dir, exist_ok=True)

    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Referer': 'https://mp.weixin.qq.com/'
    }

    response = requests.get(url, headers=headers)
    soup = BeautifulSoup(response.text, 'lxml')

    # 提取核心元素
    main_content = soup.find('div', id='js_content')
    title = soup.find('h1', class_='rich_media_title').text.strip()

    # 生成内容指纹（精确到标签结构）
    structure_hash = hashlib.sha256(str(main_content).encode()).hexdigest()

    # 高级样式配置
    css_styles = """
    <style>
        /* 专业级排版 */
        :root {
            --primary-color: #2c3e50;
            --accent-color: #3498db;
            --border-color: #ecf0f1;
        }

        .article-subtitle {
            position: relative;
            margin: 40px 0 20px;
            padding: 15px 20px;
            background: linear-gradient(145deg, #f8f9fa, #ffffff);
            border-left: 4px solid var(--accent-color);
            box-shadow: 0 3px 10px rgba(0,0,0,0.05);
            border-radius: 4px;
            transition: all 0.3s ease;
        }

        .article-subtitle:hover {
            transform: translateX(10px);
            box-shadow: 0 5px 15px rgba(52,152,219,0.2);
        }

        .article-subtitle::before {
            content: '📌';
            position: absolute;
            left: -30px;
            top: 50%;
            transform: translateY(-50%);
            font-size: 1.2em;
            color: var(--accent-color);
        }

        .subtitle-h2 {
            font-size: 1.4em;
            color: var(--primary-color);
            border-left-width: 4px;
        }

        .subtitle-h3 {
            font-size: 1.2em;
            color: #34495e;
            border-left-width: 3px;
            margin-left: 20px;
        }

        .subtitle-h4 {
            font-size: 1.1em;
            color: #7f8c8d;
            border-left-width: 2px;
            margin-left: 40px;
        }

        .content-checklist {
            position: fixed;
            right: 20px;
            top: 20px;
            background: white;
            padding: 20px;
            box-shadow: 0 0 15px rgba(0,0,0,0.1);
            border-radius: 8px;
            z-index: 1000;
        }
    </style>
    """

    # 处理内容元素
    processed = []
    element_record = []
    for idx, elem in enumerate(main_content.find_all(recursive=True), 1):
        elem_hash = hashlib.md5(str(elem).encode()).hexdigest()[:6]

        # 处理标题
        if elem.name in ['h2', 'h3', 'h4']:
            class_map = {
                'h2': 'subtitle-h2',
                'h3': 'subtitle-h3',
                'h4': 'subtitle-h4'
            }
            elem['class'] = elem.get('class', []) + ['article-subtitle', class_map[elem.name]]
            elem['data-structure-id'] = f'S-{idx}-{elem_hash}'
            processed.append(elem)
            element_record.append({
                'type': elem.name,
                'text': elem.text.strip(),
                'id': elem['data-structure-id']
            })

        # 处理图片（略，同前）...

    # 生成带目录的HTML
    html_content = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8">
        <title>{title}</title>
        {css_styles}
    </head>
    <body>
        <div class="content-checklist">
            <h3>✅ 内容清单</h3>
            <ul>
                {"".join(f'<li>[{e["type"]}] {e["text"]} <small>{e["id"]}</small></li>' for e in element_record)}
            </ul>
            <p>完整度指纹: {structure_hash}</p>
        </div>
        <!-- 文章内容... -->
    </body>
    </html>
    """

    # 保存后自动打开
    file_path = os.path.join(base_dir, f'{title}.html')
    with open(file_path, 'w', encoding='utf-8') as f:
        f.write(html_content)

    # 自动打开浏览器验证
    webbrowser.open(f'file://{os.path.abspath(file_path)}')

    return file_path

# 使用示例
final_save("你的文章链接")
